from model import predict_imagefrom flask import Flask, request, jsonifyfrom flask_cors import CORSimport osapp = Flask(__name__)CORS(app)UPLOAD_FOLDER = "uploads"os.makedirs(UPLOAD_FOLDER, exist_ok=True)@app.route("/")def home():    return "SnapTrace Backend Running"@app.route("/analyze", methods=["POST"])def analyze():    if "file" not in request.files:        return jsonify({"error": "No file uploaded"}), 400    file = request.files["file"]    if file.filename == "":        return jsonify({"error": "Empty filename"}), 400    filepath = os.path.join(UPLOAD_FOLDER, file.filename)    file.save(filepath)    # 🔥 Call model    result, confidence = predict_image(filepath)    return jsonify({     "result": result,     "confidence": confidence    })if __name__ == "__main__":    app.run(host="0.0.0.0", port=10000)    